fun solve(nums: Array<Long>): Array<Long> {
    val n = nums.size
    val ans = Array<Long>(2 * n) { 0L }

    // First n elements are the same as nums
    for (i in 0 until n) {
        ans[i] = nums[i]
    }

    // Last n elements are the reverse of nums
    for (i in 0 until n) {
        // ans[i + n] = nums[n - i - 1]
        ans[i + n] = nums[n - 1 - i]
    }

    return ans
}

